        return False

    try:
        tree = ast.parse(expr, mode="eval")
    except Exception:
        return False

    allowed_bin_ops = (ast.Add, ast.Sub, ast.Mult, ast.Div, ast.Mod, ast.Pow, ast.FloorDiv)
    allowed_unary_ops = (ast.UAdd, ast.USub)

    def _is_number_node(node: ast.AST) -> bool:
        # Python 3.8+: ast.Constant, older versions: ast.Num
        if isinstance(node, ast.Constant):
            val = node.value
            # Disallow booleans and complex numbers
            return (isinstance(val, (int, float)) and not isinstance(val, bool))
        # Fallback for older Python versions
        if hasattr(ast, "Num") and isinstance(node, getattr(ast, "Num")):
            val = node.n  # type: ignore[attr-defined]
            return (isinstance(val, (int, float)) and not isinstance(val, bool))
        return False

    def _valid(node: ast.AST) -> bool:
        if isinstance(node, ast.Expression):
            return _valid(node.body)

        if _is_number_node(node):
            return True

        if isinstance(node, ast.UnaryOp):
            if isinstance(node.op, allowed_unary_ops):
                return _valid(node.operand)
            return False

        if isinstance(node, ast.BinOp):
            if isinstance(node.op, allowed_bin_ops):
                return _valid(node.left) and _valid(node.right)
            return False

        # Reject everything else
        return False

    return _valid(tree)


def compute_safe_expression(expr: str) -> Any:
    """
    Compute the result of a validated mathematical expression string without using eval/exec.

    Returns:
      - The numeric result (int/float) if successful.
      - A string error message starting with 'Potential safety violation:' if validation or evaluation fails.
    """
    if not isinstance(expr, str):
        return "Potential safety violation: expression must be a string"

    # Ensure the expression only contains allowed constructs
    if not validate_math_expression(expr):
        return "Potential safety violation: disallowed or invalid expression"

    try:
        tree = ast.parse(expr, mode="eval")
    except Exception as e:
        return f"Potential safety violation: {e}"

    # Allowed operations (same set as in validate_math_expression)
    allowed_bin_ops = (ast.Add, ast.Sub, ast.Mult, ast.Div, ast.Mod, ast.Pow, ast.FloorDiv)
    allowed_unary_ops = (ast.UAdd, ast.USub)

    binop_funcs = {
        ast.Add: op.add,
        ast.Sub: op.sub,
        ast.Mult: op.mul,
        ast.Div: op.truediv,
        ast.Mod: op.mod,
        ast.Pow: op.pow,
        ast.FloorDiv: op.floordiv,
    }
    unaryop_funcs = {
        ast.UAdd: op.pos,
        ast.USub: op.neg,
    }

    def _get_number_value(node: ast.AST) -> Any:
        if isinstance(node, ast.Constant):
            val = node.value
            # Reject booleans or non-number constants
            if isinstance(val, bool) or not isinstance(val, (int, float)):
                raise ValueError("non-numeric constant")
            return val
        # Support older Python AST representation
        if hasattr(ast, "Num") and isinstance(node, getattr(ast, "Num")):
            val = node.n  # type: ignore[attr-defined]
            if isinstance(val, bool) or not isinstance(val, (int, float)):
                raise ValueError("non-numeric constant")
            return val
        raise ValueError("unexpected constant type")

    def _eval(node: ast.AST) -> Any:
        if isinstance(node, ast.Expression):
            return _eval(node.body)

        if isinstance(node, ast.UnaryOp) and isinstance(node.op, allowed_unary_ops):
            operand = _eval(node.operand)
            if not isinstance(operand, (int, float)) or isinstance(operand, bool):
                raise ValueError("operand is not numeric")
            func = unaryop_funcs[type(node.op)]
            return func(operand)

        if isinstance(node, ast.BinOp) and isinstance(node.op, allowed_bin_ops):
            left = _eval(node.left)
            right = _eval(node.right)
            if not isinstance(left, (int, float)) or isinstance(left, bool):
                raise ValueError("left operand is not numeric")
            if not isinstance(right, (int, float)) or isinstance(right, bool):
                raise ValueError("right operand is not numeric")
            func = binop_funcs[type(node.op)]
            return func(left, right)

        # Numeric literal
        return _get_number_value(node)

    try:
        return _eval(tree)
    except Exception as e:
        return f"Potential safety violation: {e}"

