def compute_safe_expression(expr: str) -> Any:
    """
    Compute the result of a validated mathematical expression string without using eval/exec.

    Returns:
      - The numeric result (int/float) if successful.
      - A string error message starting with 'Potential safety violation:' if validation or evaluation fails.
    """
    if not isinstance(expr, str):
        return "Potential safety violation: expression must be a string"

    # Ensure the expression only contains allowed constructs
    if not validate_math_expression(expr):
        return "Potential safety violation: disallowed or invalid expression"

